head.script:
scwin.vCurDate = "";
scwin.UserID = "";
scwin.ez110Idx = "";
scwin.ez116Idx_hdoIdx = "";
scwin.ez116Idx_bhoIdx = "";
scwin.ez116Idx_offIdx = "";
scwin.oriCarTon = "";
scwin.carTon = "";
scwin.carTon_text = "";
scwin.currentTabMode = "vehclInfo";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.UserID = $c.ses.getUserId();
    scwin.retrieveVehcl();
};

scwin.isNum = function(str) {
    let num = "0123456789";
    for (let i = 0; i < str.length; i++) {
        if (num.indexOf(str.substring(i, i + 1)) < 0) {
            return false;
        }
    }
    return true;
};

scwin.isUndefined = function(val) {
    return (typeof val === "undefined" || val === null);
};

scwin.replace = function(str, from, to) {
    if (str == null) return "";
    let result = str;
    while (result.indexOf(from) >= 0) {
        result = result.replace(from, to);
    }
    return result;
};

scwin.retrieveVehcl = async function(mode) {
    scwin.oriCarTon = "";
    let condVal1 = cond1.getValue();
    let condVal2 = cond2.getValue();
    let allVal = all.getValue();

    dma_cond.set("cond1", condVal1);
    dma_cond.set("cond2", condVal2);
    if (allVal == "1" || allVal == "true" || allVal == true) {
        dma_cond.set("all", "1");
    } else {
        dma_cond.set("all", "0");
    }

    await $c.sbm.execute(sbm_retrieveVehcl);

    if (mode != "save") {
        scwin.currentTabMode = "vehclInfo";
    }
};

scwin.sbm_retrieveVehcl_submitdone = async function(e) {
    if (ds_vehcl.getRowCount() < 1) {
        await $c.win.alert("조회결과가 없습니다.");
    } else {
        let row = ds_vehcl.getRowPosition();
        if (row >= 0) {
            scwin.f_vehclNrm(ds_vehcl.getCellData(row, "carTyp"));
        }
    }
};

scwin.sbm_retrieveVehcl_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.retrieveVlAccount = async function() {
    if (ds_vehcl.getRowCount() > 0) {
        let row = ds_vehcl.getRowPosition();
        if (ds_vehcl.getRowStatus(row) != "C") {
            ds_vlAccount.removeAll();
            dma_cond.set("cond1", ds_vehcl.getCellData(row, "ez110Idx"));
            await $c.sbm.execute(sbm_retrieveVlAccount);
        }
    }
};

scwin.sbm_retrieveVlAccount_submitdone = function(e) {
};

scwin.sbm_retrieveVlAccount_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.retrieveVlFixCost = async function() {
    if (ds_vehcl.getRowCount() > 0) {
        let row = ds_vehcl.getRowPosition();
        if (ds_vehcl.getRowStatus(row) != "C") {
            ds_vlFixCost.removeAll();
            dma_cond.set("cond1", ds_vehcl.getCellData(row, "ez110Idx"));
            await $c.sbm.execute(sbm_retrieveVlFixCost);
        }
    }
};

scwin.sbm_retrieveVlFixCost_submitdone = function(e) {
};

scwin.sbm_retrieveVlFixCost_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.retrieveVlInsurance = async function() {
    if (ds_vehcl.getRowCount() > 0) {
        let row = ds_vehcl.getRowPosition();
        if (ds_vehcl.getRowStatus(row) != "C") {
            ds_vlInsurance.removeAll();
            dma_cond.set("cond1", ds_vehcl.getCellData(row, "ez110Idx"));
            await $c.sbm.execute(sbm_retrieveVlInsurance);
        }
    }
};

scwin.sbm_retrieveVlInsurance_submitdone = function(e) {
};

scwin.sbm_retrieveVlInsurance_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.newinput = async function() {
    $c.gus.cfEnableObjects([vehclNo]);
    ds_vlAccount.removeAll();
    ds_vlFixCost.removeAll();
    ds_vlInsurance.removeAll();

    await scwin.f_defaultBlkCntrCls();

    if (ds_vehcl.getRowCount() == 0) {
        ds_vehcl.insertRow();
        autoVehcl.setValue("1");
        txt_steelVehclYn.setValue("0");
        chk_24VehclYn.setValue("1");
        scwin.oriCarTon = "";
    } else {
        let chk = 0;
        for (let i = 0; i < ds_vehcl.getRowCount(); i++) {
            if (ds_vehcl.getRowStatus(i) == "C") {
                chk++;
            }
        }
        if (chk > 0) {
            await $c.win.alert("새로운 차량정보는 하나만 입력하실수 있습니다. 저장 후 다시 추가해주세요.");
            $c.gus.cfEnableObjects([vehclNo]);
        } else {
            ds_vehcl.insertRow();
            let row = ds_vehcl.getRowPosition();
            ds_vehcl.setCellData(row, "ez110Idx", "");
            autoVehcl.setValue("1");
            txt_steelVehclYn.setValue("0");
            chk_24VehclYn.setValue("1");
        }
    }

    if (ds_temp.getRowCount() > 0) {
        let row = ds_vehcl.getRowPosition();
        ds_vehcl.setCellData(row, "blkCntrCls", ds_temp.getCellData(0, "code"));
    }
};

scwin.addVlAccount = async function() {
    let row = ds_vehcl.getRowPosition();
    if (ds_vehcl.getRowStatus(row) == "C") {
        await $c.win.alert("결제정보는 차량정보를 저장하신 후에 입력하실수 있습니다.");
    } else {
        let aRow = ds_vlAccount.getRowPosition();
        if (ds_vlAccount.getRowCount() > 0) {
            if (ds_vlAccount.getCellData(aRow, "bankCd") == "") { await $c.win.alert("은행을 선택해주세요"); return false; }
            if (ds_vlAccount.getCellData(aRow, "bankAcntNo") == "") { await $c.win.alert("계좌번호를 입력해주세요"); return false; }
            if (ds_vlAccount.getCellData(aRow, "dpstr") == "") { await $c.win.alert("예금주를 입력해주세요"); return false; }
        }
        ds_vlAccount.insertRow();
        let newRow = ds_vlAccount.getRowPosition();
        scwin.ez110Idx = ds_vehcl.getCellData(row, "ez110Idx");
        ds_vlAccount.setCellData(newRow, "ez110Idx", scwin.ez110Idx);
        let ez112 = ds_vehcl.getCellData(row, "ez112Idx");
        ds_vlAccount.setCellData(newRow, "ez112Idx", ez112);
    }
};

scwin.delVlAccount = function() {
    let row = ds_vlAccount.getRowPosition();
    if (row >= 0) {
        ds_vlAccount.removeRow(row);
    }
};

scwin.saveVlAccount = async function() {
    if (ds_vlAccount.getRowCount() > 0) {
        let aRow = ds_vlAccount.getRowPosition();
        if (ds_vlAccount.getCellData(aRow, "bankCd") == "") { await $c.win.alert("은행을 선택해주세요"); return false; }
        if (ds_vlAccount.getCellData(aRow, "bankAcntNo") == "") { await $c.win.alert("계좌번호를 입력해주세요"); return false; }
        if (ds_vlAccount.getCellData(aRow, "dpstr") == "") { await $c.win.alert("예금주를 입력해주세요"); return false; }
        await $c.sbm.execute(sbm_vlAccount);
    } else {
        await $c.win.alert("신규버튼을 클릭하신 후 데이터를 입력해주세요");
    }
};

scwin.sbm_vlAccount_submitdone = async function(e) {
    await $c.win.alert("성공적으로 저장되었습니다.");
};

scwin.sbm_vlAccount_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.addVlFixCost = async function() {
    let row = ds_vehcl.getRowPosition();
    if (ds_vehcl.getRowStatus(row) == "C") {
        await $c.win.alert("차량고정비정보는 차량정보를 저장하신 후에 입력하실수 있습니다.");
    } else {
        let fRow = ds_vlFixCost.getRowPosition();
        if (ds_vlFixCost.getRowCount() > 0) {
            if (ds_vlFixCost.getCellData(fRow, "vehclFcostAcnt") == "") { await $c.win.alert("차량고정비를 선택해주세요"); return false; }
            if (ds_vlFixCost.getCellData(fRow, "uncollNypay") == "") { await $c.win.alert("부과기준을 선택해주세요"); return false; }
            if (ds_vlFixCost.getCellData(fRow, "levyStDd") == "") { await $c.win.alert("부과시작일 입력해주세요"); return false; }
            if (ds_vlFixCost.getCellData(fRow, "levyEndDd") == "") { await $c.win.alert("부과종료일 입력해주세요"); return false; }
            if (ds_vlFixCost.getCellData(fRow, "levyDd") == "") { await $c.win.alert("부과료일 입력해주세요"); return false; }
            if (ds_vlFixCost.getCellData(fRow, "levyAmt") == "") { await $c.win.alert("부과금을 입력해주세요"); return false; }
        }
        ds_vlFixCost.insertRow();
        let newRow = ds_vlFixCost.getRowPosition();
        scwin.ez110Idx = ds_vehcl.getCellData(row, "ez110Idx");
        ds_vlFixCost.setCellData(newRow, "ez110Idx", scwin.ez110Idx);
    }
};

scwin.delVlFixCost = function() {
    let row = ds_vlFixCost.getRowPosition();
    if (row >= 0) {
        ds_vlFixCost.removeRow(row);
    }
};

scwin.saveVlFixCost = async function() {
    let fRow = ds_vlFixCost.getRowPosition();
    let levyStDdVal = ds_vlFixCost.getCellData(fRow, "levyStDd");
    let levyEndDdVal = ds_vlFixCost.getCellData(fRow, "levyEndDd");
    let levyAmtVal = ds_vlFixCost.getCellData(fRow, "levyAmt");
    let divsAmtVal = ds_vlFixCost.getCellData(fRow, "divsAmt");
    let divsYnVal = ds_vlFixCost.getCellData(fRow, "divsYn");

    if (levyStDdVal > levyEndDdVal) {
        await $c.win.alert("부과시작일이 부과종료일보다 큽니다.");
        return;
    }

    if ((divsYnVal == "1" || divsYnVal == true) && levyStDdVal.substring(0, 6) == levyEndDdVal.substring(0, 6)) {
        await $c.win.alert("부과 시작월과 부과 종료월이 같습니다.");
        return;
    }

    if (Number(levyAmtVal) < Number(divsAmtVal)) {
        await $c.win.alert("분할 금액이 부과금액보다 큽니다.");
        return;
    }

    if (ds_vlFixCost.getRowCount() > 0) {
        if (ds_vlFixCost.getCellData(fRow, "vehclFcostAcnt") == "") { await $c.win.alert("차량고정비를 선택해주세요"); return false; }
        if (ds_vlFixCost.getCellData(fRow, "uncollNypay") == "") { await $c.win.alert("부과기준을 선택해주세요"); return false; }
        if (ds_vlFixCost.getCellData(fRow, "levyStDd") == "") { await $c.win.alert("부과시작일 입력해주세요"); return false; }
        if (ds_vlFixCost.getCellData(fRow, "levyEndDd") == "") { await $c.win.alert("부과종료일 입력해주세요"); return false; }
        if (ds_vlFixCost.getCellData(fRow, "levyDd") == "") { await $c.win.alert("부과료일 입력해주세요"); return false; }
        if (ds_vlFixCost.getCellData(fRow, "levyAmt") == "") { await $c.win.alert("부과금을 입력해주세요"); return false; }
        await $c.sbm.execute(sbm_vlFixCost);
    } else {
        await $c.win.alert("신규버튼을 클릭하신 후 데이터를 입력해주세요");
    }
};

scwin.sbm_vlFixCost_submitdone = async function(e) {
    await $c.win.alert("성공적으로 저장되었습니다.");
};

scwin.sbm_vlFixCost_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.addVlInsurance = async function() {
    let row = ds_vehcl.getRowPosition();
    if (ds_vehcl.getRowStatus(row) == "C") {
        await $c.win.alert("차량보험정보는 차량정보를 저장하신 후에 입력하실수 있습니다.");
    } else {
        let iRow = ds_vlInsurance.getRowPosition();
        if (ds_vlInsurance.getRowCount() > 0) {
            if (ds_vlInsurance.getCellData(iRow, "insrCdCd") == "") { await $c.win.alert("보험사를 선택해주세요"); return false; }
            if (ds_vlInsurance.getCellData(iRow, "insrNm") == "") { await $c.win.alert("보험상품명을 입력해주세요"); return false; }
            if (ds_vlInsurance.getCellData(iRow, "grntAmt") == "") { await $c.win.alert("보장금액을 입력해주세요"); return false; }
            if (ds_vlInsurance.getCellData(iRow, "entryAmt") == "") { await $c.win.alert("가입금액을 입력해주세요"); return false; }
            if (ds_vlInsurance.getCellData(iRow, "entryDate") == "") { await $c.win.alert("가입일을 입력해주세요"); return false; }
            if (ds_vlInsurance.getCellData(iRow, "insrDueDate") == "") { await $c.win.alert("만기일을 입력해주세요"); return false; }
        }
        ds_vlInsurance.insertRow();
        let newRow = ds_vlInsurance.getRowPosition();
        scwin.ez110Idx = ds_vehcl.getCellData(row, "ez110Idx");
        ds_vlInsurance.setCellData(newRow, "ez110Idx", scwin.ez110Idx);
    }
};

scwin.delVlInsurance = function() {
    let row = ds_vlInsurance.getRowPosition();
    if (row >= 0) {
        ds_vlInsurance.removeRow(row);
    }
};

scwin.saveVlInsurance = async function() {
    if (ds_vlInsurance.getRowCount() > 0) {
        let iRow = ds_vlInsurance.getRowPosition();
        if (ds_vlInsurance.getCellData(iRow, "insrCdCd") == "") { await $c.win.alert("보험사를 선택해주세요"); return false; }
        if (ds_vlInsurance.getCellData(iRow, "insrNm") == "") { await $c.win.alert("보험상품명을 입력해주세요"); return false; }
        if (ds_vlInsurance.getCellData(iRow, "grntAmt") == "") { await $c.win.alert("보장금액을 입력해주세요"); return false; }
        if (ds_vlInsurance.getCellData(iRow, "entryAmt") == "") { await $c.win.alert("가입금액을 입력해주세요"); return false; }
        if (ds_vlInsurance.getCellData(iRow, "entryDate") == "") { await $c.win.alert("가입일을 입력해주세요"); return false; }
        if (ds_vlInsurance.getCellData(iRow, "insrDueDate") == "") { await $c.win.alert("만기일을 입력해주세요"); return false; }
        await $c.sbm.execute(sbm_vlInsurance);
    } else {
        await $c.win.alert("신규버튼을 클릭하신 후 데이터를 입력해주세요");
    }
};

scwin.sbm_vlInsurance_submitdone = async function(e) {
    await $c.win.alert("성공적으로 저장되었습니다.");
};

scwin.sbm_vlInsurance_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.savethis = async function() {
    if (ds_vehcl.getRowCount() > 0) {
        let chk = 0;

        for (let i = 0; i < ds_vehcl.getRowCount(); i++) {
            let vno = ds_vehcl.getCellData(i, "vehclNo");
            ds_vehcl.setCellData(i, "vehclNo", scwin.replace(vno, " ", ""));
            if (ds_vehcl.getRowStatus(i) == "C") {
                chk++;
            }
        }

        if (chk > 1) {
            await $c.win.alert("새로운 차량정보는 하나만 입력하실수 있습니다. 저장 후 다시 추가해주세요.");
            $c.gus.cfEnableObjects([vehclNo]);
        } else {
            let row = ds_vehcl.getRowPosition();

            if (ds_vehcl.getCellData(row, "vehclCls") == "") { await $c.win.alert("차량분류를 선택해주세요"); return false; }
            if (ds_vehcl.getCellData(row, "vehclNo") == "") { await $c.win.alert("차량번호를 입력해주세요"); return false; }
            if (ds_vehcl.getCellData(row, "blkCntrCls") == "") { await $c.win.alert("운송구분을 선택해주세요"); return false; }
            if (ds_vehcl.getCellData(row, "picNm") == "") { await $c.win.alert("기사명을 입력해 주십시오."); return false; }
            if (ds_vehcl.getCellData(row, "handphoneNo") == "") { await $c.win.alert("기사 휴대전화 번호를 입력해 주십시오."); return false; }
            if (ds_vehcl.getCellData(row, "carTyp").trim() == "") { await $c.win.alert("차종을  선택해주십시오."); return false; }
            if (carTon_combo.getValue() == "" || carTon_combo.getValue() == "선택하세요.") { await $c.win.alert("톤수를  선택해주십시오."); return false; }

            if (ds_vehcl.getCellData(row, "pdaNo") == "") {
                ds_vehcl.setCellData(row, "pdaNo", scwin.replace(ds_vehcl.getCellData(row, "handphoneNo"), "-", ""));
            }

            if (ds_vehcl.getCellData(row, "vehclCls") != "4") {
                if (ds_vehcl.getCellData(row, "prefDistrict1") == "") { await $c.win.alert("선호권역을 입력해 주십시오."); return false; }
                if (ds_vehcl.getCellData(row, "prefKcg1") == "") { await $c.win.alert("선호화종을 입력해 주십시오."); return false; }
            }

            if (ds_vehcl.getCellData(row, "vehclCls") == "3" && ds_vehcl.getCellData(row, "filenm") == "") { await $c.win.alert("서류를 첨부해주세요."); return false; }
            if (ds_vehcl.getCellData(row, "vehclCls") == "2" && ds_vehcl.getCellData(row, "filenm") == "") { await $c.win.alert("서류를 첨부해주세요."); return false; }

            let v_VehclNo = vehclNo.getValue();

            if ($c.gus.cfIsNull(pdaNo.getValue())) {
                cb_realPdaYn.setValue("0");
            }

            if (!scwin.isNum(v_VehclNo.slice(v_VehclNo.length - 4, v_VehclNo.length))) {
                await $c.win.alert("차량번호 마지막 4자리는 숫자만 입력가능합니다.");
                vehclNo.setFocus();
                return;
            }

            if (v_VehclNo.length < 7) {
                await $c.win.alert("잘못된 차량번호 입니다.");
                vehclNo.setFocus();
                return;
            }

            if (ds_vehcl.getCellData(row, "picNm").length > 4) {
                await $c.win.alert("기사명은 최대 4글자까지 가능합니다.");
                picNm.setFocus();
                return;
            }

            if (ds_vehcl.getCellData(row, "vehclCls") == "4") {
                ds_vehcl.setCellData(row, "approve", "1");
            } else {
                if (ds_vehcl.getCellData(row, "filenm") != ds_vehcl.getCellData(row, "filenm2")) {
                    ds_vehcl.setCellData(row, "approve", "0");
                    ds_vehcl.setCellData(row, "cnsntId", "");
                }
            }

            if (ds_vehcl.getUpdatedIndex().length > 0 && ds_vehcl.getCellData(row, "vehclCls") != "4") {
                ds_vehcl.setCellData(row, "approve", "0");
            }

            await $c.sbm.execute(sbm_vehcl);
            $c.gus.cfDisableObjects([vehclNo]);
        }
    } else {
        await $c.win.alert("신규등록버튼을 눌러 새로운 정보를 추가해주세요.");
    }
};

scwin.sbm_vehcl_submitdone = async function(e) {
    await $c.win.alert("성공적으로 저장되었습니다.");
    scwin.retrieveVehcl("save");
};

scwin.sbm_vehcl_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.deletethis = async function() {
    if (ds_vehcl.getRowCount() == 0) {
        await $c.win.alert("데이터가 존재하지 않습니다.");
        return false;
    }
    let chk = await $c.win.confirm("삭제하시겠습니까?");
    if (chk) {
        let row = ds_vehcl.getRowPosition();
        if (ds_vehcl.getRowStatus(row) == "C") {
            ds_vehcl.removeRow(row);
        } else {
            ds_del.removeAll();
            ds_del.insertRow();
            let delRow = ds_del.getRowPosition();
            let cond1Val = "" + ds_vehcl.getCellData(row, "ez110Idx");
            ds_del.setCellData(delRow, "cond1", cond1Val);
            ds_del.setCellData(delRow, "ez108Idx", "" + ds_vehcl.getCellData(row, "ez108Idx"));
            ds_del.setCellData(delRow, "vehclNo", "" + ds_vehcl.getCellData(row, "vehclNo"));
            ds_del.setCellData(delRow, "hdoIdx", "" + ds_vehcl.getCellData(row, "hdoIdx"));

            await $c.sbm.execute(sbm_del);
        }
        $c.gus.cfDisableObjects([vehclNo]);
    }
};

scwin.sbm_del_submitdone = async function(e) {
    if (ds_Result.getRowCount() > 0) {
        let str = ds_Result.getCellData(ds_Result.getRowPosition(), "outMsg");
