scwin.isBusiNoByValue = async function() {
    let strNo = crnNo.getValue();
    if (strNo != "") {
        let sum = 0;
        let getlist = [];
        let chkvalue = [1, 3, 7, 1, 3, 7, 1, 3, 5];

        for (let i = 0; i < 10; i++) {
            getlist[i] = Number(strNo.substring(i, i + 1));
        }

        for (let i = 0; i < 9; i++) {
            sum += getlist[i] * chkvalue[i];
        }

        sum = sum + parseInt((getlist[8] * 5) / 10);
        let sidliy = sum % 10;
        let sidchk = 0;

        if (sidliy != 0) {
            sidchk = 10 - sidliy;
        } else {
            sidchk = 0;
        }

        if (sidchk != getlist[9]) {
            await $c.win.alert("유효하지 않은 사업자번호입니다.");
            crnNo.setFocus();
        }
    }
    return true;
};

