scwin.f_fileSet = async function() {
    let row = ds_vehcl.getRowPosition();
    let obj = {
        attachFileNm: ds_vehcl.getCellData(row, "filenm"),
        attachFilePath: ds_vehcl.getCellData(row, "filepath")
    };

    let resultList = await $c.win.openPopup("/ui/bp/fbp/bi/vi/ez_104_01_02p.xml", {
        width: 650,
        height: 250,
        modal: true,
        data: obj
    });

    if (resultList != null) {
        if (resultList[0] != "" && resultList[0] != "undefined") {
            ds_vehcl.setCellData(row, "filenm", resultList[1]);
            ds_vehcl.setCellData(row, "filepath", resultList[0]);
        }
    }
};

